+    Svg,
+    /// Plain text (no ANSI codes).
+    Text,
+}
+
+impl ScreenshotFormat {
+    pub fn extension(self) -> &'static str {
+        match self {
+            Self::Html => "html",
+            Self::Svg => "svg",
+            Self::Text => "txt",
+        }
+    }
+
+    pub fn label(self) -> &'static str {
+        match self {
+            Self::Html => "HTML",
+            Self::Svg => "SVG",
+            Self::Text => "Text",
+        }
+    }
+}
